import sys

class Solution:
    def recoverHeapAfterDeletion(self, nums: list[int]) -> bool:
        duplicateRemover = set()
        for el in nums:
            if el in duplicateRemover:
                nums.remove(el)
                duplicateRemover.remove(el)
            elif el not in duplicateRemover:
                duplicateRemover.add(el)
                heapify(nums, 0, len(nums) - 1)
        return True

import heapq

def heapify(nums, i, n):
    largest = i
    left = 2 * i + 1
    right = 2 * i + 2
    if left < n and nums[left] > nums[largest]:
        largest = left
    if right < n and nums[right] > nums[largest]:
        largest = right
    if largest != i:
        nums[i], nums[largest] = nums[largest], nums[i]
        heapify(nums, largest, n)

