#include <iostream>
#include <algorithm>
#include <vector>
#include <set>

void heapify(std::vector<int>& nums, int i, int n) {
    int largest = i;
    int left = 2 * i + 1;
    int right = 2 * i + 2;
    if (left < n && nums[left] > nums[largest])
        largest = left;
    if (right < n && nums[right] > nums[largest])
        largest = right;
    if (largest != i)
    {
        std::swap(nums[i], nums[largest]);
        heapify(nums, largest, n);
    }
}

bool Solution::recoverHeapAfterDeletion(const std::vector<int>& nums) {
    std::vector<int> numsCopy = nums;
    std::set<int> duplicateRemover;
    for (int el : numsCopy)
        if (duplicateRemover.find(el) != duplicateRemover.end())
            nums.erase(std::remove(nums.begin(), nums.end(), el), nums.end());
        else
            duplicateRemover.insert(el);
    heapify(nums, 0, nums.size() - 1);
    return true;
}

int main() {
    int n;
    std::cin >> n;
    std::vector<int> nums(n);
    for (int& el : nums)
        std::cin >> el;
    Solution solution;
    std::cout << (solution.recoverHeapAfterDeletion(nums) ? 'true' : 'false');
    return 0;
}
